/*
 * Complete the 'solve' function below.
 *
 * The function takes an integer array 'arr' (1 <= arr.length <= 2 * 10^5) as input,
 * and returns an integer array of length 'arr.length'.
 * 
 * The array 'arr' contains integers arranged in ascending order. Your function should
 * return the array of integers after applying the selection sort algorithm in ascending order.
 * 
 * The selection sort algorithm works by repeatedly finding the minimum element from the
 * unsorted part of the array and swapping it with the first unsorted element.
 *
 */

#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
bool solve(vector<int>& nums) {
  int n = nums.size();
  for (int i = 0; i < n - 1; i++) {
    int minIndex = i;
    for (int j = i + 1; j < n; j++) {
      if (nums[j] < nums[minIndex]) {
        minIndex = j;
      }
    }
    // Swap minIndex and i
    swap(nums[minIndex], nums[i]);
  }
  return true;
}

